import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const SEMESTERS = [1,2,3,4,5,6,7,8];
const STATUS_BADGE = { submitted: 'badge-yellow', approved: 'badge-green', rejected: 'badge-red', draft: 'badge-gray' };

export default function HodMarks() {
  const [marks, setMarks] = useState([]);
  const [subjects, setSubjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState({ semester: '', subject: '', status: '', midExam: '' });
  const [commentModal, setCommentModal] = useState(null);
  const [comment, setComment] = useState('');
  const [actionType, setActionType] = useState('');

  const load = () => {
    const params = {};
    Object.entries(filter).forEach(([k,v]) => { if(v) params[k] = v; });
    axios.get('/api/hod/marks', { params }).then(res => { setMarks(res.data.marks); setLoading(false); });
  };

  const loadSubjects = () => {
    const params = filter.semester ? { semester: filter.semester } : {};
    axios.get('/api/hod/subjects', { params }).then(res => setSubjects(res.data.subjects));
  };

  useEffect(load, [filter]);
  useEffect(loadSubjects, [filter.semester]);

  const openAction = (mark, type) => { setCommentModal(mark); setActionType(type); setComment(''); };

  const handleAction = async () => {
    if (!commentModal) return;
    try {
      const endpoint = actionType === 'approve' ? 'approve' : actionType === 'reject' ? 'reject' : 'lock';
      await axios.put(`/api/hod/marks/${commentModal._id}/${endpoint}`, { comment });
      toast.success(`Marks ${actionType}d successfully`);
      setCommentModal(null);
      load();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Action failed');
    }
  };

  const handleBulkApprove = async () => {
    const submitted = marks.filter(m => m.status === 'submitted');
    if (!submitted.length) return toast.info('No submitted marks to approve');
    if (!window.confirm(`Approve all ${submitted.length} submitted marks?`)) return;
    try {
      await Promise.all(submitted.map(m => axios.put(`/api/hod/marks/${m._id}/approve`, { comment: 'Bulk approved' })));
      toast.success(`${submitted.length} marks entries approved`);
      load();
    } catch { toast.error('Bulk approve failed'); }
  };

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  const pendingCount = marks.filter(m => m.status === 'submitted').length;

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">Review Marks</div>
          <div className="page-subtitle">Approve or reject faculty-submitted marks</div>
        </div>
        {pendingCount > 0 && (
          <button className="btn btn-success" onClick={handleBulkApprove}>✅ Approve All ({pendingCount})</button>
        )}
      </div>

      {pendingCount > 0 && (
        <div className="warning-box">⏳ <strong>{pendingCount}</strong> marks entr{pendingCount > 1 ? 'ies are' : 'y is'} pending your approval.</div>
      )}

      <div className="filter-bar">
        <select className="form-select" style={{ width: 160 }} value={filter.semester} onChange={e => setFilter({ ...filter, semester: e.target.value, subject: '' })}>
          <option value="">All Semesters</option>
          {SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}
        </select>
        <select className="form-select" style={{ width: 200 }} value={filter.subject} onChange={e => setFilter({ ...filter, subject: e.target.value })}>
          <option value="">All Subjects</option>
          {subjects.map(s => <option key={s._id} value={s._id}>{s.name} ({s.code})</option>)}
        </select>
        <select className="form-select" style={{ width: 150 }} value={filter.midExam} onChange={e => setFilter({ ...filter, midExam: e.target.value })}>
          <option value="">All Exams</option>
          <option value="Mid-1">Mid-1</option>
          <option value="Mid-2">Mid-2</option>
        </select>
        <select className="form-select" style={{ width: 150 }} value={filter.status} onChange={e => setFilter({ ...filter, status: e.target.value })}>
          <option value="">All Status</option>
          <option value="submitted">Pending</option>
          <option value="approved">Approved</option>
          <option value="rejected">Rejected</option>
        </select>
      </div>

      <div className="card">
        <div className="table-wrapper">
          {marks.length === 0 ? (
            <div className="empty-state"><div className="empty-icon">📝</div><div className="empty-text">No marks found</div></div>
          ) : (
            <table>
              <thead>
                <tr><th>Student</th><th>Roll No</th><th>Sem</th><th>Subject</th><th>Exam</th><th>Marks</th><th>Faculty</th><th>Status</th><th>Actions</th></tr>
              </thead>
              <tbody>
                {marks.map(m => (
                  <tr key={m._id}>
                    <td className="fw-600">{m.student?.name}</td>
                    <td style={{ fontFamily: 'monospace', fontSize: 12 }}>{m.student?.rollNumber}</td>
                    <td>{m.semester}</td>
                    <td>{m.subject?.name} <span style={{ fontSize: 11, color: 'var(--text-muted)' }}>({m.subject?.code})</span></td>
                    <td><span className="badge badge-blue">{m.midExam}</span></td>
                    <td className="fw-600">{m.totalMarks} / {m.subject?.maxMidMarks || m.maxTotalMarks}</td>
                    <td className="text-muted">{m.faculty?.name}</td>
                    <td>
                      <span className={`badge ${STATUS_BADGE[m.status]}`}>{m.status}</span>
                      {m.isLocked && <span className="badge badge-red" style={{ marginLeft: 4 }}>🔒 Locked</span>}
                    </td>
                    <td>
                      <div className="gap-8">
                        {m.status === 'submitted' && (
                          <>
                            <button className="btn btn-success btn-sm" onClick={() => openAction(m, 'approve')}>✅</button>
                            <button className="btn btn-danger btn-sm" onClick={() => openAction(m, 'reject')}>❌</button>
                          </>
                        )}
                        {m.status === 'approved' && !m.isLocked && (
                          <button className="btn btn-warning btn-sm" onClick={() => openAction(m, 'lock')}>🔒 Lock</button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {commentModal && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setCommentModal(null)}>
          <div className="modal">
            <div className="modal-header">
              <span className="modal-title">
                {actionType === 'approve' ? '✅ Approve Marks' : actionType === 'reject' ? '❌ Reject Marks' : '🔒 Lock Marks'}
              </span>
              <button className="modal-close" onClick={() => setCommentModal(null)}>×</button>
            </div>
            <div className="modal-body">
              <p style={{ marginBottom: 14, fontSize: 14 }}>
                <strong>{commentModal.student?.name}</strong> — {commentModal.subject?.name} ({commentModal.midExam}) —
                Score: <strong>{commentModal.totalMarks}/{commentModal.subject?.maxMidMarks || 30}</strong>
              </p>
              {actionType !== 'lock' && (
                <div className="form-group">
                  <label className="form-label">Comment (optional)</label>
                  <textarea className="form-input" rows={3} value={comment} onChange={e => setComment(e.target.value)} placeholder="Add a comment..." style={{ resize: 'vertical' }} />
                </div>
              )}
            </div>
            <div className="modal-footer">
              <button className="btn btn-outline" onClick={() => setCommentModal(null)}>Cancel</button>
              <button
                className={`btn ${actionType === 'approve' ? 'btn-success' : actionType === 'reject' ? 'btn-danger' : 'btn-warning'}`}
                onClick={handleAction}
              >
                Confirm {actionType.charAt(0).toUpperCase() + actionType.slice(1)}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
